import{_ as o,C as a,c as l,o as i,j as t,G as s,a2 as r,a as p}from"./chunks/framework.DrNAj9nU.js";const k="/assets/token-2.BfxbIG04.png",c="/assets/token-1.xmZ5A1hn.png",f=JSON.parse('{"title":"AI模型中的Token：理解语言模型的基本单位","description":"","frontmatter":{},"headers":[],"relativePath":"column/AIFuture/基础认知/AI模型中的token是什么.md","filePath":"column/AIFuture/基础认知/AI模型中的token是什么.md","lastUpdated":1773825228000}'),u={name:"column/AIFuture/基础认知/AI模型中的token是什么.md"};function d(g,e,h,m,_,b){const n=a("ArticleMetadata");return i(),l("div",null,[e[0]||(e[0]=t("h1",{id:"ai模型中的token-理解语言模型的基本单位",tabindex:"-1"},[p("AI模型中的Token：理解语言模型的基本单位 "),t("a",{class:"header-anchor",href:"#ai模型中的token-理解语言模型的基本单位","aria-label":'Permalink to "AI模型中的Token：理解语言模型的基本单位"'},"​")],-1)),s(n),e[1]||(e[1]=r('<nav class="table-of-contents"><ul><li><a href="#一、什么是token">一、什么是Token</a></li><li><a href="#二、token在模型中的作用">二、Token在模型中的作用</a></li><li><a href="#三、token与语言差异">三、Token与语言差异</a></li><li><a href="#四、token的实际应用场景">四、Token的实际应用场景</a></li><li><a href="#五、总结">五、总结</a></li></ul></nav><p>在人工智能尤其是大语言模型（LLM）中，“token”是一个非常基础但关键的概念。理解token的概念，对于深入掌握AI模型的工作原理、优化提示词以及控制成本都有重要意义。本文将系统讲解token的定义、作用以及在实际应用中的影响。</p><h2 id="一、什么是token" tabindex="-1">一、什么是Token <a class="header-anchor" href="#一、什么是token" aria-label="Permalink to &quot;一、什么是Token&quot;">​</a></h2><p>1.1 <strong>基本定义</strong> 在自然语言处理（NLP）中，token是指文本的最小处理单位。它可以是：</p><ul><li>一个单词（如英语中的 “apple”）</li><li>一个字（如中文的“苹果”可能被分为“苹”“果”）</li><li>甚至是一个子词或符号（subword）</li></ul><p>大语言模型在处理文本时，并不是直接理解整句话，而是先将文本拆分成一系列token，然后基于这些token进行计算和预测。</p><p>1.2 <strong>为什么不直接用字符或单词</strong></p><ul><li>字符：单位太小，模型需要处理的序列太长，计算成本高</li><li>单词：单位太大，可能导致词汇表过大，不易处理罕见词</li><li>token（子词）：折中方案，既能表示常见单词，也能拆分罕见词，提高模型效率</li></ul><div class="tip custom-block"><p class="custom-block-title">模型token计算网站</p><p><a href="https://token-caculator.static.tezign.com/" target="_blank" rel="noreferrer">https://token-caculator.static.tezign.com/</a></p><p><img src="'+k+`" alt="" loading="lazy"></p></div><h2 id="二、token在模型中的作用" tabindex="-1">二、Token在模型中的作用 <a class="header-anchor" href="#二、token在模型中的作用" aria-label="Permalink to &quot;二、Token在模型中的作用&quot;">​</a></h2><p>2.1 <strong>语言建模的核心</strong> LLM的本质是<strong>预测下一个token的概率</strong>。也就是说，模型通过上下文，判断下一个token最可能是什么，从而生成自然语言。</p><p>示例：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>输入：我今天想吃</span></span>
<span class="line"><span>模型预测下一个token：苹果</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>2.2 <strong>序列长度与上下文管理</strong> 每个模型都有最大token长度限制，例如GPT-4的上下文窗口可能是8192个token。超出限制的内容可能被截断，因此理解token长度对于处理长文档非常重要。</p><p>2.3 <strong>成本与消耗</strong> 在商用模型中，API调用费用通常按token计费：</p><ul><li>输入token：用户输入文本被拆分成的token数</li><li>输出token：模型生成的token数</li></ul><p>理解token的拆分方式有助于控制成本，例如将中文文本合理分段、避免冗长提示词。</p><h2 id="三、token与语言差异" tabindex="-1">三、Token与语言差异 <a class="header-anchor" href="#三、token与语言差异" aria-label="Permalink to &quot;三、Token与语言差异&quot;">​</a></h2><p>不同语言的token长度和拆分方式差异较大：</p><ul><li><strong>英文</strong>：空格天然分词，token通常比单词少</li><li><strong>中文</strong>：没有空格，token通常按字或子词拆分</li><li><strong>符号与标点</strong>：也可能被单独作为token</li></ul><p>因此，同样长度的文本，在不同语言中生成的token数量可能差异很大。</p><h2 id="四、token的实际应用场景" tabindex="-1">四、Token的实际应用场景 <a class="header-anchor" href="#四、token的实际应用场景" aria-label="Permalink to &quot;四、Token的实际应用场景&quot;">​</a></h2><p>4.1 <strong>提示词优化（Prompt Engineering）</strong> 通过控制token数量，可以：</p><ul><li>避免超出上下文窗口</li><li>减少API费用</li><li>提高模型理解效率</li></ul><p>4.2 <strong>长文本处理</strong></p><ul><li>长文档可以先拆成多个token块，再逐块处理</li><li>使用RAG（检索增强生成）时，将文档切分为token后向量化，以便快速检索</li></ul><p>4.3 <strong>计量和成本管理</strong></p><ul><li>API费用透明化：根据token数量预测成本</li><li>可以通过减少无用token和重复文本优化成本</li></ul><h2 id="五、总结" tabindex="-1">五、总结 <a class="header-anchor" href="#五、总结" aria-label="Permalink to &quot;五、总结&quot;">​</a></h2><p>Token是大语言模型处理文本的基本单位，它既不是简单的字符，也不是单纯的单词，而是一种折中方式，使模型能够高效地理解和生成自然语言。掌握token的概念和使用方法，有助于：</p><ul><li>优化提示词设计</li><li>控制长文本处理策略</li><li>精准估算模型调用成本</li></ul><p>一句话总结：</p><blockquote><p><strong>Token = 模型理解语言的最小单元，是AI生成语言的基础砖块。</strong></p></blockquote><p><strong>图解如下：</strong></p><p><img src="`+c+'" alt="token-1.png" width="500" loading="lazy"></p>',35))])}const A=o(u,[["render",d]]);export{f as __pageData,A as default};
